content:
export TARGET := riscv64gc-unknown-none-elf
export MODE   ?= release
export BOARD  ?= qemu-virt

export ROOT			:= $(shell pwd)
export TARGET_DIR 	:= $(ROOT)/target/$(TARGET)/$(MODE)

export ROOTFS  ?= $(ROOT)/part/img/sdcard.img

export TESTFS  ?= $(ROOT)/fs.img


export SBI ?= $(ROOT)/part/bin/rustsbi-qemu.bin

KERNEL_ELF := ./target/$(TARGET)/$(MODE)/pantheon
KERNEL_BIN := $(KERNEL_ELF).bin

TFTPBOOT := /work/tftpboot/

SDCARD_BAK = $(ROOTFS).bak
FS_BAK = $(TESTFS).bak
# FS_IMG_DIR := .

TEST_DIR := ./tests/final
FS_IMG := ./sdcard.img

export OBJCOPY := rust-objcopy --binary-architecture=riscv64


build: 
	mkdir -p .cargo
	cp -rf cargo-config/* .cargo
	cd pantheon/kernel && make build

QFLAGS := 
QFLAGS += -m 128
QFLAGS += -machine virt 
QFLAGS += -nographic
QFLAGS += -smp 1
QFLAGS += -kernel kernel-qemu
QFLAGS += -drive file=$(SDCARD_BAK),if=none,format=raw,id=x0 
QFLAGS += -device virtio-blk-device,drive=x0,bus=virtio-mmio-bus.0 
QFLAGS += -device virtio-net-device,netdev=net -netdev user,id=net
ifeq ($(BOARD), qemu-virt)
	QFLAGS += -bios sbi-qemu
endif


backup: 
	@cp $(ROOTFS) $(SDCARD_BAK) 

# fs-backup: 
# 	@cp $(TESTFS) $(FS_BAK) 

sbi-qemu:
	@cp $(SBI) sbi-qemu

run: sbi-qemu build backup
	@cp $(KERNEL_BIN) kernel-qemu
	qemu-system-riscv64 $(QFLAGS)
	rm -f $(SDCARD_BAK)

qemu-dtb:backup
	qemu-system-riscv64 $(QFLAGS) -machine dumpdtb=qemu.dtb
	@dtc -o qemu.dts -O dts -I dtb qemu.dtb
	rm -f $(ROOTFS)
	mv $(SDCARD_BAK) $(ROOTFS)

debug: build
	qemu-system-riscv64 $(QFLAGS) -s -S

debug-client:
	@riscv64-unknown-elf-gdb -ex 'file $(KERNEL_BIN)' -ex 'set arch riscv:rv64' -ex 'target remote localhost:1234'

clean:
	@rm -f kernel-qemu
	@rm -f sbi-qemu
	@rm -f sdcard.img
	cargo clean

sdcard:
	@echo "\e[49;34m\e[1m----------Making sdcard-----------\e[0m"
	@rm -f $(FS_IMG)
	@dd if=/dev/zero of=$(FS_IMG) count=2048 bs=1M
	@sudo losetup -f $(FS_IMG)
	@mkfs.ext4  -F -O ^metadata_csum_seed $(FS_IMG)
	@mkdir -p mnt
	@sudo mount $(FS_IMG) mnt
	@sudo cp -r $(TEST_DIR)/* mnt
	@sudo umount mnt
	@sudo rm -rf mnt
	@sudo chmod 777 $(FS_IMG)
	@echo "\e[49;34m\e[1m----------Making sdcard finished-----------\e[0m"


build-gui:
	@echo "\e[49;34m\e[1m----------Building user-----------\e[0m"
	@cd pantheon/user/apps && make build
	@echo "\e[49;34m\e[1m----------Making fs.img-----------\e[0m"
	@./make_fs.sh
	@echo "\e[49;34m\e[1m----------Building kernel---------\e[0m"
	@cd pantheon/kernel && make kernel

run-uitest: sbi-qemu
	@echo "\e[49;34m\e[1m----------GUI Test-----------\e[0m"
	@cp $(KERNEL_BIN) kernel-qemu
	@qemu-system-riscv64 \
		-machine virt \
		-nographic \
		-kernel kernel-qemu \
		-drive file=$(TESTFS),if=none,format=raw,id=x0 \
		-vnc :0\
	        -device virtio-blk-device,drive=x0,bus=virtio-mmio-bus.0 \
		-device virtio-net-device,netdev=net -netdev user,id=net\
		-device virtio-gpu-device,xres=640,yres=480\
		-device virtio-mouse-device\
		-device virtio-keyboard-device

gnvc:
	@echo "\e[49;34m\e[1m----------Open Viewer-----------\e[0m"
	gvncviewer localhost

board:
	@cp $(TARGET_DIR)/pantheon.bin  $(TFTPBOOT)


all: sbi-qemu build
	@cp $(KERNEL_BIN) kernel-qemu

.PHONY: all build run debug clean debug-client sbi-qemu backup sdcard build-gui board

[package]
edition = "2021"
name = "pantheon"
version = "0.1.0"

[features]
multicore = []
dev = []
vf2 = ["config/vf2"]
qemu_riscv = ["config/qemu_riscv"]
busybox = []
preliminary = []
customized-sh = []
runtests = []
uitest = []
ramdisk = []


[dependencies]
# Local crates
config = {path = "../lib/config", default-features = false}
klog   = {path = "../lib/klog"}
kmem   = {path = "../lib/kmem"}
hart   = {path = "../lib/hart"}
kalloc = {path = "../lib/kalloc"}
utils  = {path = "../lib/utils"}
nix    = {path = "../lib/nix"}
arch    = {path = "../lib/arch"}
trap   = {path = "../lib/trap"}
vfs   = {path = "../lib/vfs"}
task   = {path = "../lib/task"}
kpath  = {path = "../lib/kpath" }
ksync  = {path = "../lib/ksync" }
fat32  = {path = "../lib/fat32" }
executor = {path = "../lib/executor"}
ktime = {path = "../lib/ktime" }

virtio-drivers2 = {path = "../lib/virtio-drivers2" }


lwext4_rust = {path = "../lib/lwext4_rust"}

fdt = { git = "https://github.com/repnop/fdt" }
sbi-rt = { version = "0.0.2", features = ["legacy"] }
visionfive2-sd = { path = "../lib/visionfive2-sd-0.1.0"}

# External crates
log  = "0"
spin = "0"
riscv = "0"
bitflags = "1.2.1"
xmas-elf = "0.9.0"
virtio-drivers = "0.6.0"
crate_interface = "0.1"
hashbrown = "0.14"
lazy_static = { version = "1.4.0", features = ["spin_no_std"] }
kernel-sync = { git = "https://github.com/os-module/kernel-sync.git" }
smoltcp = { version = "0.11.0", default-features = false, features = [
    "alloc",
    "log",
    "medium-ethernet",
    "medium-ip",
    "proto-ipv4",
    "proto-ipv6",
    "proto-dhcpv4",
    "proto-ipv4-fragmentation",
    "socket-udp",
    "socket-tcp",
    "socket-dhcpv4",
    "async",
    "log",
] }
rand_core = "0.6.4"
num-traits = { version = "0.2",default-features = false }
num-derive = "0.3"
managed = { version = "0.8.0",default-features = false, features=["map"] }

[build-dependencies]
config = {path = "../lib/config", default-features = false}
